import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function getCreditScore(walletAddress) {
  const [txns, balances, activity] = await Promise.all([
    client.TransactionService.getTransactionsForAddressV3("eth-mainnet", walletAddress),
    client.BalanceService.getTokenBalancesForWalletAddress("eth-mainnet", walletAddress),
    client.AllChainsService.getAddressActivity(walletAddress),
  ]);
  const txCount = txns.data?.items?.length ?? 0;
  const netWorth = balances.data?.items?.reduce((s, i) => s + (i.quote ?? 0), 0) ?? 0;
  const chainsActive = activity.data?.items?.length ?? 0;
  const score = Math.min(100, txCount * 0.5 + netWorth * 0.001 + chainsActive * 5);
  return { walletAddress, score: Math.round(score), txCount, netWorth, chainsActive };
}
